1	// FCM fan-out helpers.
2	// Stub: logs payload + sends to every token on the user/admin profile(s).
3	// TODO(Aok): wire delivery-receipt cleanup of stale tokens (spec §11).
4	
5	import { getMessaging, type MulticastMessage } from "firebase-admin/messaging";
6	import { db } from "./admin";
7	
8	export type NotificationPayload = {
9	  title: string;
10	  body: string;
11	  deepLink: string;
12	  data?: Record<string, string>;
13	};
14	
15	async function fanOut(tokens: string[], payload: NotificationPayload): Promise<void> {
16	  if (tokens.length === 0) {
17	    console.log("[fcm] no tokens to send to:", payload.title);
18	    return;
19	  }
20	  const msg: MulticastMessage = {
21	    tokens,
22	    notification: { title: payload.title, body: payload.body },
23	    data: { ...(payload.data ?? {}), deepLink: payload.deepLink },
24	  };
25	  try {
26	    const res = await getMessaging().sendEachForMulticast(msg);
27	    console.log(`[fcm] sent ${res.successCount}/${tokens.length}: ${payload.title}`);
28	  } catch (e) {
29	    console.error("[fcm] send error", e);
30	  }
31	}
32	
33	export async function sendToUser(uid: string, payload: NotificationPayload): Promise<void> {
34	  const snap = await db.doc(`users/${uid}`).get();
35	  const tokens = (snap.data()?.fcmTokens as string[] | undefined) ?? [];
36	  await fanOut(tokens, payload);
37	}
38	
39	export async function sendToAdmins(payload: NotificationPayload): Promise<void> {
40	  const snap = await db.collection("users").where("role", "==", "admin").get();
41	  const tokens: string[] = [];
42	  for (const doc of snap.docs) {
43	    const t = (doc.data().fcmTokens as string[] | undefined) ?? [];
44	    tokens.push(...t);
45	  }
46	  await fanOut(tokens, payload);
47	}

