1	// Admin-callable: approve a pending request, decrement stock atomically,
2	// return list of eligible drones for the assignment step.
3	// Spec: §10 approveRequest, flow F-16.
4	
5	import { HttpsError, onCall } from "firebase-functions/v2/https";
6	import { z } from "zod";
7	import { db, FieldValue, Timestamp } from "../lib/admin";
8	import { requireAdmin } from "../lib/roles";
9	import { haversineKm } from "../lib/geo";
10	
11	const InputSchema = z.object({ reqId: z.string().min(1) });
12	
13	const RANGE_KM = 15;
14	const MIN_BATTERY = 30;
15	
16	export const approveRequest = onCall(async (req) => {
17	  const { uid: adminUid } = await requireAdmin(req);
18	  const parsed = InputSchema.safeParse(req.data);
19	  if (!parsed.success) throw new HttpsError("invalid-argument", parsed.error.message);
20	
21	  const reqRef = db.doc(`requests/${parsed.data.reqId}`);
22	
23	  // Transaction: validate stock again under lock, then decrement + flip status.
24	  const totals = await db.runTransaction(async (tx) => {
25	    const reqSnap = await tx.get(reqRef);
26	    if (!reqSnap.exists) throw new HttpsError("not-found", "Request not found.");
27	    const r = reqSnap.data() ?? {};
28	    if (r.status !== "pending") {
29	      throw new HttpsError("failed-precondition", `Cannot approve a ${r.status} request.`);
30	    }
31	
32	    // Load every catalog item we're about to decrement.
33	    const items = (r.items ?? []) as { catalogId: string; qty: number }[];
34	    const catalogRefs = items.map((i) => db.doc(`catalog/${i.catalogId}`));
35	    const catalogSnaps = await Promise.all(catalogRefs.map((ref) => tx.get(ref)));
36	    for (let i = 0; i < items.length; i++) {
37	      const snap = catalogSnaps[i];
38	      if (!snap.exists) throw new HttpsError("not-found", `Item ${items[i].catalogId} missing.`);
39	      const d = snap.data() ?? {};
40	      if ((d.stock ?? 0) < items[i].qty) {
41	        throw new HttpsError("failed-precondition", `Item ${d.name} is now out of stock.`);
42	      }
43	    }
44	
45	    // Decrement stock + flip request status.
46	    for (let i = 0; i < items.length; i++) {
47	      tx.update(catalogRefs[i], { stock: FieldValue.increment(-items[i].qty) });
48	    }
49	    tx.update(reqRef, {
50	      status: "approved",
51	      decidedBy: adminUid,
52	      decidedAt: Timestamp.now(),
53	    });
54	    return r;
55	  });
56	
57	  // Fetch idle drones, filter by payload + range + battery.
58	  const droneSnap = await db.collection("drones").where("status", "==", "idle").get();
59	  const dest = (totals.deliveryAddress as { lat: number; lng: number });
60	  const eligible = droneSnap.docs
61	    .map((d) => ({ id: d.id, ...d.data() } as Record<string, unknown> & { id: string }))
62	    .filter((d) => {
63	      const base = d.baseLocation as { lat: number; lng: number } | undefined;
64	      const maxPayload = (d.maxPayloadKg as number | undefined) ?? 0;
65	      const battery = (d.batteryPct as number | undefined) ?? 0;
66	      if (!base) return false;
67	      if (battery < MIN_BATTERY) return false;
68	      if (maxPayload < (totals.totalWeightKg as number)) return false;
69	      if (haversineKm(base, dest) > RANGE_KM) return false;
70	      return true;
71	    });
72	
73	  return { eligibleDrones: eligible };
74	});
75

